module reg_file(input wire clk,
                input wire wr_en,
                input wire [9:0] w_addr,
                input wire [9:0] r_addr,
                input wire [17:0] w_data,
                output reg [17:0] r_data,
                output reg [17:0] r_data2);

  reg [17:0] ram [0:1023];

  always @(posedge clk)
  begin
    r_data <= ram[r_addr];
  end

  always @(posedge clk)
  begin
    if (wr_en)
      ram[w_addr] <= w_data;
    r_data2 <= ram[w_addr];
  end

endmodule
